import { useState } from 'react';
import {
    Box,
    Button,
    Grid,
    Typography,
    IconButton,
    Card,
    CardMedia,
} from '@mui/material';
import {
    Add as AddIcon,
    Delete as DeleteIcon,
} from '@mui/icons-material';
import PhotoBookPage from './PhotoBookPage';

const PhotoBookPages = ({ format, photos }) => {
    const [pages, setPages] = useState([{ id: 0, photos: [] }]);
    const [selectedPhotos, setSelectedPhotos] = useState([]);

    const handleAddPage = () => {
        setPages(prevPages => [
            ...prevPages,
            { id: prevPages.length, photos: [] }
        ]);
    };

    const handleDeletePage = (pageId) => {
        setPages(prevPages => prevPages.filter(page => page.id !== pageId));
    };

    const handlePhotoAdd = (pageNumber, position, photo) => {
        setPages(prevPages => {
            const newPages = [...prevPages];
            const page = newPages[pageNumber];
            if (page) {
                page.photos = [
                    ...page.photos.filter(p => p.position !== position),
                    { ...photo, position }
                ];
            }
            return newPages;
        });
        setSelectedPhotos(prev => [...prev, photo.id]);
    };

    const handlePhotoRemove = (pageNumber, position) => {
        setPages(prevPages => {
            const newPages = [...prevPages];
            const page = newPages[pageNumber];
            if (page) {
                const removedPhoto = page.photos.find(p => p.position === position);
                if (removedPhoto) {
                    setSelectedPhotos(prev => prev.filter(id => id !== removedPhoto.id));
                }
                page.photos = page.photos.filter(p => p.position !== position);
            }
            return newPages;
        });
    };

    const handlePhotoEdit = (pageNumber, position, editedBlob) => {
        setPages(prevPages => {
            const newPages = [...prevPages];
            const page = newPages[pageNumber];
            if (page) {
                const photo = page.photos.find(p => p.position === position);
                if (photo) {
                    const editedFile = new File([editedBlob], photo.file.name, {
                        type: 'image/jpeg'
                    });
                    photo.file = editedFile;
                    photo.preview = URL.createObjectURL(editedBlob);
                }
            }
            return newPages;
        });
    };

    return (
        <Box sx={{ width: '100%', p: 2 }}>
            <Box sx={{ mb: 4 }}>
                <Typography variant="h5" gutterBottom align="center">
                    Создание страниц фотокниги
                </Typography>
                <Typography variant="subtitle1" color="text.secondary" gutterBottom align="center">
                    Перетащите фотографии на страницы
                </Typography>
            </Box>

            <Grid container spacing={2} sx={{ mb: 4 }}>
                <Grid item xs={12} md={3}>
                    <Typography variant="h6" gutterBottom>
                        Доступные фотографии
                    </Typography>
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                        {photos.filter(photo => !selectedPhotos.includes(photo.id)).map((photo) => (
                            <Card
                                key={photo.id}
                                sx={{ width: 100, height: 100 }}
                                draggable
                                onDragStart={(e) => {
                                    e.dataTransfer.setData('photo/id', photo.id);
                                }}
                            >
                                <CardMedia
                                    component="img"
                                    height="100"
                                    image={photo.preview}
                                    alt={photo.file.name}
                                    sx={{ objectFit: 'cover' }}
                                />
                            </Card>
                        ))}
                    </Box>
                </Grid>

                <Grid item xs={12} md={9}>
                    {pages.map((page, index) => (
                        <Box key={page.id} sx={{ position: 'relative' }}>
                            <PhotoBookPage
                                format={format}
                                photos={page.photos}
                                onPhotoAdd={handlePhotoAdd}
                                onPhotoRemove={handlePhotoRemove}
                                onPhotoEdit={handlePhotoEdit}
                                pageNumber={index}
                            />
                            {pages.length > 1 && (
                                <IconButton
                                    size="small"
                                    onClick={() => handleDeletePage(page.id)}
                                    sx={{ position: 'absolute', top: 0, right: 0 }}
                                    color="error"
                                >
                                    <DeleteIcon />
                                </IconButton>
                            )}
                        </Box>
                    ))}

                    <Button
                        variant="outlined"
                        startIcon={<AddIcon />}
                        onClick={handleAddPage}
                        sx={{ mt: 2 }}
                        fullWidth
                    >
                        Добавить страницу
                    </Button>
                </Grid>
            </Grid>
        </Box>
    );
};

export default PhotoBookPages;
